const err = $input.first().json;
const node = err.execution && err.execution.lastNodeExecuted || 'unknown node';
const msg = err.execution && err.execution.error && err.execution.error.message || 'unknown error';
const wf = err.workflow && err.workflow.name || 'pipeline';

const text = `⚠️ <b>Pipeline failed</b>\n<b>Workflow:</b> ${wf}\n<b>Failed at:</b> <code>${node}</code>\n<b>Error:</b> <code>${msg.substring(0, 300)}</code>`;

const botToken = $env.PIPELINE_BOT_TOKEN;
const chatId = $env.PIPELINE_CHAT_ID;

if (!botToken || !chatId) {
  throw new Error('PIPELINE_BOT_TOKEN or PIPELINE_CHAT_ID env vars not set');
}

return [{ json: {
  url: `https://api.telegram.org/bot${botToken}/sendMessage`,
  body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
} }];
